-- 1. Notificações dos usuários de teste (5112 registros)
DELETE FROM notifications WHERE userId IN (
  SELECT id FROM users WHERE name LIKE 'Integration User%' OR name LIKE 'Test Admin%'
);

-- 2. Badges dos usuários de teste
DELETE FROM user_badges WHERE userId IN (
  SELECT id FROM users WHERE name LIKE 'Integration User%' OR name LIKE 'Test Admin%'
);

-- 3. Membros de bolão de teste
DELETE FROM pool_members WHERE userId IN (
  SELECT id FROM users WHERE name LIKE 'Integration User%' OR name LIKE 'Test Admin%'
);

-- 4. Palpites de teste
DELETE FROM bets WHERE userId IN (
  SELECT id FROM users WHERE name LIKE 'Integration User%' OR name LIKE 'Test Admin%'
);

-- 5. Preferências de notificação de teste
DELETE FROM notification_preferences WHERE userId IN (
  SELECT id FROM users WHERE name LIKE 'Integration User%' OR name LIKE 'Test Admin%'
);

-- 6. Planos de usuários de teste
DELETE FROM user_plans WHERE userId IN (
  SELECT id FROM users WHERE name LIKE 'Integration User%' OR name LIKE 'Test Admin%'
);

-- 7. Finalmente, deletar os usuários de teste
DELETE FROM users WHERE name LIKE 'Integration User%' OR name LIKE 'Test Admin%';

